CharacterReader(String input) {
    Validate.notNull(input);

    this.input = input;
    this.length = input.length();
}

String consumeToEnd() {
    String data = input.substring(pos, input.length());
    pos = input.length();
    return data;
}

additional_testcases.testcase:
@Test public void consumeToEndWhenEmpty() {
    String in = "";
    CharacterReader r = new CharacterReader(in);
    String toEnd = r.consumeToEnd();
    assertEquals("", toEnd);
    assertTrue(r.isEmpty());
}

@Test public void consumeToEndAfterPartialConsume() {
    String in = "hello world";
    CharacterReader r = new CharacterReader(in);
    r.consume();
    String toEnd = r.consumeToEnd();
    assertEquals("ello world", toEnd);
    assertTrue(r.isEmpty());
}
